<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu-like Desktop Environment</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
        }

        body {
            overflow: hidden;
            width: 100vw;
            height: 100vh;
        }

        /* Desktop */
        #desktop {
            position: relative;
            width: 100%;
            height: 100%;
            background: linear-gradient(135deg, #2e3440 0%, #3b4252 100%);
            overflow: hidden;
        }

        /* Taskbar */
        #taskbar {
            position: absolute;
            bottom: 0;
            left: 0;
            width: 100%;
            height: 48px;
            background-color: rgba(31, 35, 41, 0.9);
            display: flex;
            align-items: center;
            justify-content: center;
            backdrop-filter: blur(5px);
            z-index: 1000;
        }

        .launcher {
            width: 48px;
            height: 48px;
            margin: 0 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            border-radius: 50%;
            transition: background-color 0.2s;
        }

        .launcher:hover {
            background-color: rgba(255, 255, 255, 0.1);
        }

        .launcher-icon {
            width: 32px;
            height: 32px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 24px;
            color: white;
        }

        #open-files .launcher-icon {
            background-color: #1e9c4a;
        }

        #open-notepad .launcher-icon {
            background-color: #0d65d8;
        }

        /* Windows */
        .window {
            position: absolute;
            width: 600px;
            height: 400px;
            min-width: 360px;
            min-height: 240px;
            background-color: rgba(46, 52, 64, 0.95);
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.5);
            display: flex;
            flex-direction: column;
            overflow: hidden;
            backdrop-filter: blur(10px);
        }

        .window-header {
            height: 32px;
            background-color: #4c566a;
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0 8px;
            cursor: default;
            user-select: none;
        }

        .window-title {
            color: white;
            font-size: 14px;
            margin-left: 8px;
        }

        .window-controls {
            display: flex;
            gap: 6px;
        }

        .win-close {
            width: 20px;
            height: 20px;
            border-radius: 50%;
            background-color: #bf616a;
            color: white;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            font-size: 12px;
        }

        .win-close:hover {
            background-color: #d35f5f;
        }

        .window-content {
            flex: 1;
            overflow: auto;
            padding: 16px;
            color: white;
        }

        /* Files Window */
        #files-window {
            top: 10%;
            left: 20%;
        }

        #files-path-container {
            display: flex;
            align-items: center;
            margin-bottom: 16px;
            background-color: rgba(31, 35, 41, 0.8);
            padding: 8px 12px;
            border-radius: 4px;
        }

        #files-path {
            color: #88c0d0;
            font-size: 16px;
            margin-left: 8px;
        }

        .fs-up-btn {
            display: flex;
            align-items: center;
            justify-content: center;
            width: 32px;
            height: 32px;
            border-radius: 4px;
            background-color: rgba(136, 192, 208, 0.2);
            cursor: pointer;
        }

        .fs-up-btn:hover {
            background-color: rgba(136, 192, 208, 0.4);
        }

        #files-list {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(120px, 1fr));
            gap: 16px;
        }

        .fs-item {
            display: flex;
            flex-direction: column;
            align-items: center;
            padding: 8px;
            border-radius: 4px;
            cursor: pointer;
            transition: background-color 0.2s;
        }

        .fs-item:hover {
            background-color: rgba(136, 192, 208, 0.2);
        }

        .fs-icon {
            width: 48px;
            height: 48px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 24px;
            margin-bottom: 8px;
        }

        .fs-item-name {
            text-align: center;
            font-size: 14px;
            word-break: break-word;
        }

        /* Notepad Window */
        #notepad-window {
            top: 15%;
            left: 30%;
        }

        #tabs {
            display: flex;
            background-color: #4c566a;
            border-bottom: 1px solid #3b4252;
        }

        .tab {
            padding: 8px 16px;
            cursor: pointer;
            color: white;
            font-size: 14px;
            display: flex;
            align-items: center;
            gap: 8px;
            border-right: 1px solid #3b4252;
        }

        .tab.active {
            background-color: rgba(255, 255, 255, 0.1);
            border-top: 2px solid #88c0d0;
        }

        .tab:hover:not(.active) {
            background-color: rgba(255, 255, 255, 0.05);
        }

        .close-tab {
            width: 16px;
            height: 16px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 10px;
            color: white;
            cursor: pointer;
        }

        .close-tab:hover {
            background-color: rgba(255, 0, 0, 0.3);
        }

        #editor-container {
            flex: 1;
            position: relative;
            overflow: hidden;
        }

        #editor {
            width: 100%;
            height: 100%;
            background-color: rgba(46, 52, 64, 0.9);
            color: white;
            border: none;
            padding: 16px;
            font-family: 'Monospace', monospace;
            font-size: 14px;
            resize: none;
            outline: none;
        }

        #new-tab-btn {
            width: 32px;
            height: 32px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            color: white;
            border-left: 1px solid #3b4252;
        }

        #new-tab-btn:hover {
            background-color: rgba(255, 255, 255, 0.1);
        }

        /* Dragging */
        .dragging {
            cursor: move;
        }
    </style>
</head>
<body>
    <div id="desktop">
        <!-- Files Window -->
        <div id="files-window" class="window" style="display: none;">
            <div class="window-header" data-draggable="true">
                <div class="window-title">Files</div>
                <div class="window-controls">
                    <div class="win-close">×</div>
                </div>
            </div>
            <div class="window-content">
                <div id="files-path-container">
                    <div class="fs-up-btn" id="files-up">↑</div>
                    <span id="files-path">/</span>
                </div>
                <div id="files-list"></div>
            </div>
        </div>

        <!-- Notepad Window -->
        <div id="notepad-window" class="window" style="display: none;">
            <div class="window-header" data-draggable="true">
                <div class="window-title">Notepad</div>
                <div class="window-controls">
                    <div class="win-close">×</div>
                </div>
            </div>
            <div class="window-content" style="padding: 0; overflow: hidden;">
                <div id="tabs"></div>
                <div id="new-tab-btn">+</div>
                <div id="editor-container">
                    <textarea id="editor" placeholder="Type here..."></textarea>
                </div>
            </div>
        </div>

        <!-- Taskbar -->
        <div id="taskbar">
            <div class="launcher" id="open-files">
                <div class="launcher-icon">📁</div>
            </div>
            <div class="launcher" id="open-notepad">
                <div class="launcher-icon">📝</div>
            </div>
        </div>
    </div>

    <script>
        // File system data structure
        const fileSystem = {
            '/': ['bin', 'etc', 'home', 'usr', 'var'],
            '/bin': ['bash', 'ls', 'cat', 'cp', 'mv'],
            '/etc': ['config', 'hosts', 'passwd'],
            '/home': ['user'],
            '/home/user': ['Documents', 'Downloads', 'Pictures', 'Music', 'Videos'],
            '/home/user/Documents': ['report.txt', 'notes.md'],
            '/home/user/Downloads': ['file1.zip', 'image.png'],
            '/home/user/Pictures': ['wallpaper.jpg', 'screenshot.png'],
            '/usr': ['bin', 'lib', 'share'],
            '/var': ['log', 'cache', 'tmp']
        };

        // Files window state
        let currentPath = '/';

        // Notepad state
        let tabs = [];
        let activeTabId = null;

        // DOM Elements
        const desktop = document.getElementById('desktop');
        const filesWindow = document.getElementById('files-window');
        const notepadWindow = document.getElementById('notepad-window');
        const openFilesBtn = document.getElementById('open-files');
        const openNotepadBtn = document.getElementById('open-notepad');
        const filesPath = document.getElementById('files-path');
        const filesList = document.getElementById('files-list');
        const filesUpBtn = document.getElementById('files-up');
        const tabsContainer = document.getElementById('tabs');
        const editor = document.getElementById('editor');
        const newTabBtn = document.getElementById('new-tab-btn');

        // Files Window Functions
        function updateFilesPath() {
            filesPath.textContent = currentPath;

            // Update up button visibility
            if (currentPath === '/') {
                filesUpBtn.style.visibility = 'hidden';
            } else {
                filesUpBtn.style.visibility = 'visible';
            }
        }

        function renderFilesList() {
            filesList.innerHTML = '';

            const items = fileSystem[currentPath] || [];

            // Show parent directory if not at root
            if (currentPath !== '/') {
                const parentPath = currentPath.substring(0, currentPath.lastIndexOf('/')) || '/';

                const upItem = document.createElement('div');
                upItem.className = 'fs-item';
                upItem.innerHTML = `
                    <div class="fs-icon">⬆️</div>
                    <div class="fs-item-name">.. (Parent)</div>
                `;
                upItem.addEventListener('click', function() {
                    currentPath = parentPath;
                    updateFilesPath();
                    renderFilesList();
                });
                filesList.appendChild(upItem);
            }

            // Render items
            items.forEach(item => {
                const itemDiv = document.createElement('div');
                itemDiv.className = 'fs-item';

                const isDirectory = Array.isArray(fileSystem[`${currentPath}/${item}`]);
                const icon = isDirectory ? '📁' : '📄';

                itemDiv.innerHTML = `
                    <div class="fs-icon">${icon}</div>
                    <div class="fs-item-name">${item}</div>
                `;

                if (isDirectory) {
                    itemDiv.addEventListener('dblclick', function() {
                        currentPath = `${currentPath}/${item}`;
                        updateFilesPath();
                        renderFilesList();
                    });
                }

                filesList.appendChild(itemDiv);
            });
        }

        // Notepad Functions
        function generateTabId() {
            return 'tab-' + Date.now().toString(36) + Math.random().toString(36).substr(2);
        }

        function createTab(title = 'Untitled', content = '') {
            const tabId = generateTabId();
            tabs.push({ id: tabId, title, content });

            if (tabs.length === 1 || activeTabId === null) {
                activeTabId = tabId;
            }

            renderTabs();
            return tabId;
        }

        function renderTabs() {
            tabsContainer.innerHTML = '';

            tabs.forEach(tab => {
                const tabDiv = document.createElement('div');
                tabDiv.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;

                // Tab title with close button
                const titleSpan = document.createElement('span');
                titleSpan.textContent = tab.title;

                const closeBtn = document.createElement('div');
                closeBtn.className = 'close-tab';
                closeBtn.innerHTML = '×';
                closeBtn.addEventListener('click', function(e) {
                    e.stopPropagation();
                    closeTab(tab.id);
                });

                tabDiv.appendChild(titleSpan);
                tabDiv.appendChild(closeBtn);

                tabDiv.addEventListener('click', function() {
                    activeTabId = tab.id;
                    renderTabs();
                    editor.value = tab.content;
                });

                tabsContainer.appendChild(tabDiv);
            });

            // Update editor content when switching tabs
            if (activeTabId) {
                const activeTab = tabs.find(t => t.id === activeTabId);
                if (activeTab) {
                    editor.value = activeTab.content;
                }
            } else {
                editor.value = '';
            }
        }

        function closeTab(tabId) {
            const index = tabs.findIndex(t => t.id === tabId);
            if (index === -1) return;

            // Save content before removing
            if (activeTabId === tabId && tabs.length > 1) {
                updateActiveTabContent();
            }

            tabs.splice(index, 1);

            // If we closed the active tab, switch to another one
            if (activeTabId === tabId) {
                if (tabs.length > 0) {
                    activeTabId = tabs[Math.min(index, tabs.length - 1)].id;
                } else {
                    activeTabId = null;
                }
            }

            renderTabs();
            saveNotepadState();
        }

        function updateActiveTabContent() {
            const tab = tabs.find(t => t.id === activeTabId);
            if (tab) {
                tab.content = editor.value;
            }
        }

        function saveNotepadState() {
            localStorage.setItem('notepad_tabs', JSON.stringify(tabs));
            localStorage.setItem('notepad_active_tab', activeTabId);
        }

        function loadNotepadState() {
            const savedTabs = localStorage.getItem('notepad_tabs');
            if (savedTabs) {
                tabs = JSON.parse(savedTabs);

                // Restore editor content for each tab
                tabs.forEach(tab => {
                    if (!tab.content) tab.content = '';
                });

                activeTabId = localStorage.getItem('notepad_active_tab') || (tabs.length > 0 ? tabs[0].id : null);
            } else {
                // Create initial empty tab
                createTab();
            }
        }

        // Window Dragging Functionality
        function setupWindowDragging() {
            const windows = document.querySelectorAll('.window');

            windows.forEach(window => {
                const header = window.querySelector('[data-draggable="true"]');

                if (!header) return;

                let isDragging = false;
                let startX, startY, initialLeft, initialTop;

                header.addEventListener('mousedown', function(e) {
                    // Don't drag if clicking on close button
                    if (e.target.classList.contains('win-close') || 
                        e.target.closest('.win-close')) {
                        return;
                    }

                    isDragging = true;
                    startX = e.clientX;
                    startY = e.clientY;

                    const rect = window.getBoundingClientRect();
                    initialLeft = rect.left;
                    initialTop = rect.top;

                    window.classList.add('dragging');
                });

                document.addEventListener('mousemove', function(e) {
                    if (!isDragging) return;

                    const dx = e.clientX - startX;
                    const dy = e.clientY - startY;

                    let newLeft = initialLeft + dx;
                    let newTop = initialTop + dy;

                    // Keep window within viewport
                    const maxWidth = window.innerWidth - 100;
                    const maxHeight = window.innerHeight - 100;

                    newLeft = Math.max(0, Math.min(newLeft, maxWidth));
                    newTop = Math.max(0, Math.min(newTop, maxHeight));

                    window.style.left = `${newLeft}px`;
                    window.style.top = `${newTop}px`;
                });

                document.addEventListener('mouseup', function() {
                    if (isDragging) {
                        isDragging = false;
                        window.classList.remove('dragging');
                    }
                });
            });
        }

        // Event Listeners
        openFilesBtn.addEventListener('click', function() {
            filesWindow.style.display = 'flex';
            updateFilesPath();
            renderFilesList();

            // Bring to front
            filesWindow.style.zIndex = 100;
        });

        openNotepadBtn.addEventListener('click', function() {
            notepadWindow.style.display = 'flex';
            loadNotepadState();

            // Bring to front
            notepadWindow.style.zIndex = 100;
        });

        // Close buttons
        filesWindow.querySelectorAll('.win-close').forEach(btn => {
            btn.addEventListener('click', function() {
                filesWindow.style.display = 'none';
            });
        });

        notepadWindow.querySelectorAll('.win-close').forEach(btn => {
            btn.addEventListener('click', function() {
                updateActiveTabContent();
                saveNotepadState();
                notepadWindow.style.display = 'none';
            });
        });

        // Files up button
        filesUpBtn.addEventListener('click', function() {
            if (currentPath !== '/') {
                currentPath = currentPath.substring(0, currentPath.lastIndexOf('/')) || '/';
                updateFilesPath();
                renderFilesList();
            }
        });

        // New tab button
        newTabBtn.addEventListener('click', function() {
            updateActiveTabContent();
            createTab();
            saveNotepadState();
        });

        // Editor content change
        editor.addEventListener('input', function() {
            if (activeTabId) {
                const tab = tabs.find(t => t.id === activeTabId);
                if (tab) {
                    tab.content = editor.value;
                }
            }
        });

        // Initialize
        document.addEventListener('DOMContentLoaded', function() {
            setupWindowDragging();

            // Create initial notepad state if needed
            loadNotepadState();

            // Set initial files path
            currentPath = '/';
            updateFilesPath();
            renderFilesList();
        });
    </script>
</body>
</html>
